import{_ as i,o as e,c as l,e as a}from"./app-def54fd2.js";const s="/assets/image-20230910171726917-07e7e39a.png",r="/assets/image-20230910171754823-342de875.png",t="/assets/image-20230910171823971-824bf365.png",p={},d=a('<h1 id="击穿、穿透、雪崩" tabindex="-1"><a class="header-anchor" href="#击穿、穿透、雪崩" aria-hidden="true">#</a> 击穿、穿透、雪崩</h1><p>使用缓存的过程中会存在各种各样的问题，以下简单介绍几种常见的问题。</p><h2 id="缓存雪崩" tabindex="-1"><a class="header-anchor" href="#缓存雪崩" aria-hidden="true">#</a> 缓存雪崩</h2><p>缓存机器意外发生了全盘宕机，所有并发流量就会直接到达数据库，此时就算重启数据库，也会被流量给打死。</p><p><img src="'+s+'" alt="image-20230910171726917"></p><p>简单解决方案：</p><ul><li>事前：Redis 高可用，主从+哨兵，Redis cluster，避免全盘崩溃。</li><li>事中：本地 ehcache 缓存 + 限流&amp;降级，避免 MySQL 被打死。</li><li>事后：Redis 持久化，一旦重启，自动从磁盘上加载数据，快速恢复缓存数据。</li></ul><p>限流&amp;降级：</p><ul><li>限流组件确保了每秒只有多少个请求能通过，保障数据库的安全。</li><li>用户的请求不会被完全处理。</li></ul><h2 id="缓存穿透" tabindex="-1"><a class="header-anchor" href="#缓存穿透" aria-hidden="true">#</a> 缓存穿透</h2><ol><li>查询某个Key对应的数据，Redis缓存中没有相应的数据</li><li>数据库中也不存在要查询的数据，则数据库会返回空，而Redis也不会缓存这个空结果</li><li>造成每次通过这样的Key去查询数据都会直接到数据库中查询，Redis不会缓存空结果。这就造成了缓存穿透的问题。</li></ol><p>例如：支付系统中提供一个订单查询接口，由于缓存中没有数据，数据库也没有数据，此时有可能被利用，导致数据库被打死</p><blockquote><p>实际情况可能不会发生，因为数据库也会分库，也会有类似 hmac 的校验</p></blockquote><p><img src="'+r+'" alt="image-20230910171754823"></p><p>简单解决方案：</p><ul><li><p>API入口，对参数进行校验，过滤非法值。</p></li><li><p>数据库中没有查询到数据，此时写一个空值（或者默认值）到缓存里去，并设置过期时间，缓存失效之前，都可以直接从缓存中取数据。</p><ul><li>需要额外的系统资源，如果真的存在恶意漏洞，也是一个问题。</li><li>过期时间需要很好的设置，例如如果查询是走的查询库，数据同步虽然时间很短，也是有可能会查询不到数据，此时会有短期内的数据查询不到。</li></ul></li><li><p>布隆过滤器</p><ul><li>key 不存在于布隆过滤器中，此时数据就一定不存在，系统可以立即返回不存在。</li><li>key 存在于布隆过滤器中，则继续再向缓存中查询。</li><li>存在误判可能</li></ul></li></ul><h2 id="缓存击穿" tabindex="-1"><a class="header-anchor" href="#缓存击穿" aria-hidden="true">#</a> 缓存击穿</h2><p>缓存击穿，就是说某个 key 非常热点，访问非常频繁，处于集中式高并发访问的情况，当这个 key 在失效的瞬间，大量的请求就击穿了缓存，直接请求数据库，就像是在一道屏障上凿开了一个洞。</p><p><img src="'+t+'" alt="image-20230910171823971"></p><ul><li>若缓存的数据是基本不会发生更新的，则可尝试将该热点数据设置为永不过期。</li><li>若缓存的数据更新不频繁，且缓存刷新的整个流程耗时较少的情况下，则可以采用基于 Redis、zookeeper 等分布式中间件的分布式互斥锁，或者本地互斥锁以保证仅少量的请求能请求数据库并重新构建缓存，其余线程则在锁释放后能访问到新缓存。</li><li>若缓存的数据更新频繁或者在缓存刷新的流程耗时较长的情况下，可以利用定时线程在缓存过期前主动地重新构建缓存或者延后缓存的过期时间，以保证所有的请求能一直访问到对应的缓存。</li><li>缓存预热，根据当前业务进行相关热点数据的提取加载到缓存，例如定时触发。</li></ul><h2 id="区别" tabindex="-1"><a class="header-anchor" href="#区别" aria-hidden="true">#</a> 区别</h2><p>缓存击穿看着有点像缓存雪崩，其实它两区别是：</p><ul><li>缓存雪崩是指数据库压力过大甚至down机</li><li>缓存击穿只是大量并发请求到了DB数据库层面</li><li>缓存击穿可以认为是缓存雪崩的一个子集。也可以认为它俩区别，是区别在于击穿针对某一热点key缓存，雪崩则是很多key。</li></ul>',23),c=[d];function h(o,n){return e(),l("div",null,c)}const u=i(p,[["render",h],["__file","击穿穿透雪崩.html.vue"]]);export{u as default};
